export const demoProducts: Product[] = productsRaw.map(([sku, name, brandSlug, categorySlug, unit, priceCents, inStock, featured, imageUrl]) => {
  const brand = demoBrands.find((b) => b.slug === brandSlug)!;
  const category = demoCategories.find((c) => c.slug === categorySlug)!;
  const slug = `${slugify(name)}-${sku.toLowerCase()}`;
  const shortDescription = brand.name === "Diversos" ? `${category.name}.` : `${category.name} • linha ${brand.name}.`;
  return {
    id: `product-${sku}`,
    siteId: site.id,
    brandId: brand.id,
    categoryId: category.id,
    sku,
    slug,
    name,
    shortDescription,
    description: `${shortDescription} Confirme disponibilidade, especificação e aplicação correta com a equipe Náutica Color.`,
    priceCents,
    unit,
    imageUrl,
    active: true,
    featured: featured === 1,
    demoPrice: false,
    stockStatus: inStock === 1 ? "available" : "on_request",
    tags: [brand.name, category.name],
    brand,
    category
  };
});

